oxy_webhelp_navlinks = {"k8s_workload_protection-d27243e19998":{"topics":[{"title":"Deployment architecture for Kubernetes protection","shortdesc":"<p class=\"shortdesc\">For the data protection deployment architecture in Kubernetes protection, <span class=\"ph\">RSC<\/span> serves as the control plane and stores the Persistent Volume backups on         a Rubrik cluster.<\/p>","href":"kubernetes\/k8s_deployment_architecture.html","attributes":{"data-id":"k8s_deployment_architecture"},"menu":{"hasChildren":false},"tocID":"k8s_deployment_architecture-d27243e20009","topics":[]},{"title":"Kubernetes protection prerequisites","shortdesc":"<p class=\"shortdesc\">There are common and specific prerequisites for Kubernetes protection.<\/p>","href":"kubernetes\/k8s_prereqs.html","attributes":{"data-id":"k8s_prereqs"},"menu":{"hasChildren":false},"tocID":"k8s_prereqs-d27243e20023","next":"k8s_prereqs-d27243e20023"},{"title":"Kubernetes protection requirements","shortdesc":"<p class=\"shortdesc\">You can use <span class=\"ph\">Rubrik Security Cloud<\/span> to secure your on-premise or public cloud         Kubernetes clusters by protecting either entire Kubernetes namespaces or specific subsets         within a namespace using the protection set filtering feature.<\/p>","href":"kubernetes\/k8s_protection.html","attributes":{"data-id":"k8s_protection"},"menu":{"hasChildren":false},"tocID":"k8s_protection-d27243e20119","next":"k8s_protection-d27243e20119"},{"title":"Kubernetes cluster onboarding","shortdesc":"<p class=\"shortdesc\">To onboard your Kubernetes cluster, add it to your <span class=\"ph\">RSC<\/span> domain and         provide <span class=\"ph\">RSC<\/span> with access to the cluster and sufficient         permissions.<\/p>","href":"kubernetes\/k8s_cluster_onboard_discover_rsc.html","attributes":{"data-id":"k8s_cluster_onboard_discover_rsc"},"menu":{"hasChildren":false},"tocID":"k8s_cluster_onboard_discover_rsc-d27243e20256","next":"k8s_cluster_onboard_discover_rsc-d27243e20256"},{"title":"Least privilege configuration for Kubernetes","shortdesc":"<p class=\"shortdesc\">You can set up your Kubernetes kubeconfig with the least privileges so that only         minimal RBAC permissions are assigned to users and service accounts.<\/p>","href":"kubernetes\/least_privilege_configuration_K8S.html","attributes":{"data-id":"least_privilege_configuration_K8S"},"menu":{"hasChildren":false},"tocID":"least_privilege_configuration_K8S-d27243e20393","next":"least_privilege_configuration_K8S-d27243e20393"},{"title":"Kubernetes labels","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> integrates with Kubernetes native labels to manage data         protection, enabling you to use Kubernetes labels to identify and group resources, and then         associate those labels with SLA Domains.<\/p>","href":"kubernetes\/kubernetes_labels.html","attributes":{"data-id":"kubernetes_labels"},"menu":{"hasChildren":false},"tocID":"kubernetes_labels-d27243e20448","next":"kubernetes_labels-d27243e20448"},{"title":"Protection sets for Kubernetes cluster workloads","shortdesc":"<p class=\"shortdesc\">A Kubernetes cluster protection set is a protectable workload that you create and         protect using <span class=\"ph\">RSC<\/span>. A protection set might include an entire Kubernetes         namespace or a subset of resources within the namespace.<\/p>","href":"kubernetes\/k8s_cluster_protection_set.html","attributes":{"data-id":"k8s_cluster_protection_set"},"menu":{"hasChildren":false},"tocID":"k8s_cluster_protection_set-d27243e20524","next":"k8s_cluster_protection_set-d27243e20524"},{"title":"Browse Kubernetes snapshots","shortdesc":"<p class=\"shortdesc\">You can use <span class=\"ph\">RSC<\/span> to browse the resources in a Kubernetes snapshot for         protection sets and virtual machines.<\/p>","href":"kubernetes\/k8s_browse_kubernetes_snapshots.html","attributes":{"data-id":"k8s_browse_kubernetes_snapshots"},"menu":{"hasChildren":false},"tocID":"k8s_browse_kubernetes_snapshots-d27243e20620","next":"k8s_browse_kubernetes_snapshots-d27243e20620"},{"title":"OpenShift Virtual Machine workload","shortdesc":"<p class=\"shortdesc\">You can use <span class=\"ph\">RSC<\/span> to protect containers and virtual machines managed on         Kubernetes OpenShift clusters.<\/p>","href":"kubernetes\/k8s_openshift_clusters.html","attributes":{"data-id":"k8s_openshift_clusters"},"menu":{"hasChildren":false},"tocID":"k8s_openshift_clusters-d27243e20645","next":"k8s_openshift_clusters-d27243e20645"},{"title":"Kubernetes workload protection policies","shortdesc":"<p class=\"shortdesc\">In <span class=\"ph\">RSC<\/span>, you can take both policy-based and on-demand snapshots of         Kubernetes protection sets.<\/p>","href":"kubernetes\/k8s_workload_protection_policies.html","attributes":{"data-id":"k8s_workload_protection_policies"},"menu":{"hasChildren":false},"tocID":"k8s_workload_protection_policies-d27243e20777","next":"k8s_workload_protection_policies-d27243e20777"},{"title":"Kubernetes snapshot retention","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> allows changing the retention period of Kubernetes snapshots with         the help of SLA Domains. Kubernetes snapshot retention works only with Rubrik clusters         running Rubrik CDM version 7.0.2-p2 and later.<\/p>","href":"kubernetes\/k8s_snapshot_retention.html","attributes":{"data-id":"k8s_snapshot_retention"},"menu":{"hasChildren":false},"tocID":"k8s_snapshot_retention-d27243e20838","next":"k8s_snapshot_retention-d27243e20838"},{"title":"StorageClass mapping for Kubernetes","shortdesc":"<p class=\"shortdesc\"><code class=\"ph codeph\">StorageClass<\/code> mapping provides the ability to select or define new         storage tiers when restoring Kubernetes workloads to a different cluster or         environment.<\/p>","href":"kubernetes\/k8s_storage_class_mapping.html","attributes":{"data-id":"k8s_storage_class_mapping"},"menu":{"hasChildren":false},"tocID":"k8s_storage_class_mapping-d27243e20873","next":"k8s_storage_class_mapping-d27243e20873"},{"title":"<span class=\"ph\">RSC<\/span> Custom resource definitions","shortdesc":"<p class=\"shortdesc\">You can use the <span class=\"ph\">RSC<\/span> custom resource definitions to create custom         resources for backup and recovery workflows using APIs native to Kubernetes.<\/p>","href":"kubernetes\/K8s_crd_rsc.html","attributes":{"data-id":"K8s_crd_rsc"},"menu":{"hasChildren":false},"tocID":"K8s_crd_rsc-d27243e20920","next":"K8s_crd_rsc-d27243e20920"},{"title":"<span class=\"ph\">Anomaly Detection<\/span> for Kubernetes","shortdesc":"<p class=\"shortdesc\">You can enable <span class=\"ph\">Anomaly Detection<\/span> for Kubernetes virtual machines and protection         sets to identify and analyze anomalous events that can indicate a ransomware         attack.<\/p>","href":"kubernetes\/anomaly_detection_k8.html","attributes":{"data-id":"anomaly_detection_k8"},"menu":{"hasChildren":false},"tocID":"anomaly_detection_k8-d27243e21366","topics":[]}]}};